  1	import * as React from 'react';
  2	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
  3	import {
  4	  healthStateMap,
  5	  csvStatusMap,
  6	} from '@odf/shared/dashboards/status-card/states';
  7	import { useCustomPrometheusPoll } from '@odf/shared/hooks/custom-prometheus-poll';
  8	import { StorageClusterModel } from '@odf/shared/models';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { getGVK } from '@odf/shared/utils';
 11	import {
 12	  PrometheusResult,
 13	  PrometheusResponse,
 14	} from '@openshift-console/dynamic-plugin-sdk';
 15	import { HealthBody } from '@openshift-console/dynamic-plugin-sdk-internal';
 16	import {
 17	  Flex,
 18	  FlexItem,
 19	  Card,
 20	  CardBody,
 21	  CardHeader,
 22	  CardTitle,
 23	} from '@patternfly/react-core';
 24	import { ACM_ENDPOINT, HUB_CLUSTER_NAME } from '../../../../constants';
 25	import { StorageDashboard, STATUS_QUERIES } from '../../queries';
 26	import {
 27	  StorageSystemPopup,
 28	  ODFOperatorPopup,
 29	  SystemHealthMap,
 30	  CSVStatusMap,
 31	} from './storage-system-popup';
 32	import './status-card.scss';
 33	
 34	type SubSystemMap = {
 35	  [key: string]: string;
 36	};
 37	
 38	const getUniqueKey = (namespace: string, clusterName: string) =>
 39	  `${namespace}-${clusterName}`;
 40	
 41	const getWorstHealth = (healthData: SystemHealthMap[]) =>
 42	  healthData.reduce(
 43	    (acc: string, item: SystemHealthMap) =>
 44	      acc < item?.rawHealthData ? item?.rawHealthData : acc,
 45	    '0'
 46	  );
 47	
 48	const getUnifiedHealthValue = (
 49	  sysHealthVal: string,
 50	  subSysHealthVal: string
 51	) =>
 52	  !!subSysHealthVal
 53	    ? sysHealthVal < subSysHealthVal
 54	      ? subSysHealthVal
 55	      : sysHealthVal
 56	    : sysHealthVal;
 57	
 58	const setSubSystemMap = (
 59	  subSysHealthData: PrometheusResponse,
 60	  subSystemMap: SubSystemMap
 61	) =>
 62	  // ToDo (epic 4422): Assuming "namespace" in "odf_system.*"" metrics (except "odf_system_map" which is pushed by ODF opr and already has "target_namespace")
 63	  // is where system is deployed (update query if needed).
 64	  subSysHealthData?.data?.result?.forEach(
 65	    (item: PrometheusResult) =>
 66	      !item?.metric.managedBy &&
 67	      item?.metric.system_type === 'OCS' &&
 68	      (subSystemMap[
 69	        getUniqueKey(item?.metric.target_namespace, item?.metric.cluster)
 70	      ] = item?.value[1])
 71	  );
 72	
 73	const setHealthData = (
 74	  sysHealthData: PrometheusResponse,
 75	  healthData: SystemHealthMap[],
 76	  subSystemMap: SubSystemMap
 77	) =>
 78	  // ToDo (epic 4422): Assuming "namespace" in "odf_system.*"" metrics (except "odf_system_map" which is pushed by ODF opr and already has "target_namespace")
 79	  // is where system is deployed (update query if needed).
 80	  sysHealthData?.data?.result?.forEach((item: PrometheusResult) => {
 81	    const { apiGroup } = getGVK(item?.metric.target_kind);
 82	    const healthVal = item?.value[1];
 83	    const unifiedHealthVal = getUnifiedHealthValue(
 84	      healthVal,
 85	      subSystemMap[
 86	        getUniqueKey(item?.metric.target_namespace, item?.metric.cluster)
 87	      ]
 88	    );
 89	    healthData.push({
 90	      systemName: item?.metric?.storage_system,
 91	      rawHealthData:
 92	        apiGroup === StorageClusterModel.apiGroup
 93	          ? unifiedHealthVal
 94	          : healthVal,
 95	    });
 96	  });
 97	
 98	const StorageSystemHealthItem: React.FC = () => {
 99	  const { t } = useCustomTranslation();
100	
101	  const [worstHealth, setWorstHealth] = React.useState<string>('');
102	  const [sysHealthData, sysHealthError, sysHealthLoading] =
103	    useCustomPrometheusPoll({
104	      endpoint: 'api/v1/query' as any,
105	      query: STATUS_QUERIES[StorageDashboard.SYSTEM_HEALTH],
106	      basePath: ACM_ENDPOINT,
107	      cluster: HUB_CLUSTER_NAME,
108	    });
109	  const [subSysHealthData, subSysHealthError, subSysHealthLoading] =
110	    useCustomPrometheusPoll({
111	      endpoint: 'api/v1/query' as any,
112	      query: STATUS_QUERIES[StorageDashboard.HEALTH],
113	      basePath: ACM_ENDPOINT,
114	      cluster: HUB_CLUSTER_NAME,
115	    });
116	
117	  const parsedHealthData = React.useMemo(() => {
118	    const healthData: SystemHealthMap[] = [];
119	    const subSystemMap = {};
120	    !subSysHealthError &&
121	      !subSysHealthLoading &&
122	      setSubSystemMap(subSysHealthData, subSystemMap);
123	    !sysHealthError &&
124	      !sysHealthLoading &&
125	      setHealthData(sysHealthData, healthData, subSystemMap);
126	    setWorstHealth(getWorstHealth(healthData));
127	    return healthData;
128	  }, [
129	    sysHealthData,
130	    subSysHealthData,
131	    sysHealthError,
132	    subSysHealthError,
133	    sysHealthLoading,
134	    subSysHealthLoading,
135	  ]);
136	
137	  return parsedHealthData.length > 0 ? (
138	    <HealthItem
139	      title={t('Systems')}
140	      state={healthStateMap(worstHealth)}
141	      maxWidth="25rem"
142	    >
143	      <StorageSystemPopup systemHealthMap={parsedHealthData} />
144	    </HealthItem>
145	  ) : null;
146	};
147	
148	/**
149	 * For system health metrics, '0' means healthy.
150	 * For csv status metrics, '0' means unhealthy.
151	 */
152	const getWorstStatus = (csvStatusData: CSVStatusMap[]) =>
153	  csvStatusData.some((item: CSVStatusMap) => item?.rawCSVData !== '1')
154	    ? '0'
155	    : '1';
156	
157	const setCSVStatusData = (
158	  csvData: PrometheusResponse,
159	  csvStatusData: CSVStatusMap[]
160	) =>
161	  csvData?.data?.result?.forEach((item: PrometheusResult) =>
162	    csvStatusData.push({
163	      rawCSVData: item?.value[1],
164	    })
165	  );
166	
167	const CSVStatusHealthItem: React.FC = () => {
168	  const { t } = useCustomTranslation();
169	
170	  const [worstStatus, setWorstStatus] = React.useState<string>('');
171	  const [csvData, csvError, csvLoading] = useCustomPrometheusPoll({
172	    endpoint: 'api/v1/query' as any,
173	    query: STATUS_QUERIES[StorageDashboard.CSV_STATUS],
174	    basePath: ACM_ENDPOINT,
175	    cluster: HUB_CLUSTER_NAME,
176	  });
177	
178	  const parsedCSVData = React.useMemo(() => {
179	    let csvStatusData = [];
180	    !csvError && !csvLoading && setCSVStatusData(csvData, csvStatusData);
181	    setWorstStatus(getWorstStatus(csvStatusData));
182	    return csvStatusData;
183	  }, [csvData, csvError, csvLoading]);
184	
185	  return parsedCSVData.length > 0 ? (
186	    <HealthItem title={t('Data Foundation')} state={csvStatusMap(worstStatus)}>
187	      <ODFOperatorPopup csvStatusMap={parsedCSVData} />
188	    </HealthItem>
189	  ) : null;
190	};
191	
192	export const StatusCard: React.FC = () => {
193	  const { t } = useCustomTranslation();
194	
195	  return (
196	    <Card data-test="status-card">
197	      <CardHeader>
198	        <CardTitle>{t('Status')}</CardTitle>
199	      </CardHeader>
200	      <CardBody>
201	        <HealthBody>
202	          <Flex
203	            justifyContent={{ default: 'justifyContentSpaceBetween' }}
204	            className="odf-StatusCard__items--width"
205	          >
206	            <FlexItem>
207	              <CSVStatusHealthItem />
208	            </FlexItem>
209	            <FlexItem>
210	              <StorageSystemHealthItem />
211	            </FlexItem>
212	          </Flex>
213	        </HealthBody>
214	      </CardBody>
215	    </Card>
216	  );
217	};

